export function IcoAIVoice() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Glow */}
      <circle cx="100" cy="56" r="38" fill={palette.accent} opacity="0.08" />
      {/* Microphone body */}
      <rect x="84" y="20" width="32" height="52" rx="16" fill={palette.accent} />
      {/* Mic stand */}
      <path d="M 70,66 Q 70,88 100,88 Q 130,88 130,66" fill="none" stroke={palette.mid} strokeWidth="3" strokeLinecap="round" />
      <line x1="100" y1="88" x2="100" y2="108" stroke={palette.mid} strokeWidth="3" strokeLinecap="round" />
      {/* Sparkle stars */}
      {[
        [142, 22, 8],
        [158, 48, 6],
        [42, 38, 7],
        [55, 20, 5],
      ].map(([x, y, s], i) => (
        <g key={i}>
          <line x1={x} y1={y - s} x2={x} y2={y + s} stroke={palette.accent} strokeWidth="2.5" strokeLinecap="round" />
          <line x1={x - s} y1={y} x2={x + s} y2={y} stroke={palette.accent} strokeWidth="2.5" strokeLinecap="round" />
        </g>
      ))}
    </svg>
  );
}
